// ====== Utility: Commission / Fee ======
export function calcCommission(gold, workshopLevel, basePrice, threshold = 500) {
    if (gold <= threshold)
        return basePrice;
    const rate = Math.min(0.05, workshopLevel * 0.005);
    return basePrice + Math.floor(gold * rate);
}
export function calcStockFee(workshopLevel) {
    return Math.min(50, workshopLevel * 5);
}
export function get2048Size(workshopLevel) {
    const sizes = [4];
    if (workshopLevel >= 4)
        sizes.push(6);
    if (workshopLevel >= 8)
        sizes.push(8);
    return sizes;
}
